import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AgentPipelineOutput, LessonManifest } from "../types/pipeline";
import { GEMINI_PRO_MODEL } from "../constants";

// Re-export types for consumers
export * from "../types/pipeline";

export interface PronunciationResult {
  score: number;
  feedback: string;
  wordScores: { text: string; score: 'high' | 'medium' | 'low' | 'none' }[];
}

// --- HELPER: ROBUST JSON PARSING ---
const cleanJsonOutput = (text: string): string => {
  if (!text) return "{}";
  let cleaned = text.trim();
  // Remove markdown code blocks
  cleaned = cleaned.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");
  return cleaned;
};

// Initialize the client
const getClient = (): GoogleGenAI => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not defined");
  }
  return new GoogleGenAI({ apiKey });
};

// --- SYSTEM PROMPT: THE 5 AGENTS ---
const MULTI_AGENT_SYSTEM_PROMPT = `
You are a Sequential AI Pipeline consisting of 5 specialized agents working in a chain. 
Your goal is to transform a raw textbook page image into a high-fidelity Gamified Lesson.

You MUST execute these steps in order. The output of one agent informs the next.

### 🕵️ AGENT 1: THE VISION SCANNER
Analyze the image layout. Map the structure.
- Detect 'VISUAL_PUZZLE' if you see mazes, connect-the-dots, or hidden objects.
- Detect 'COMIC_STRIP' if you see panels with speech bubbles.
- Detect 'GRAMMAR_TABLE' if you see boxes with rules (e.g., "I am / You are").
- Detect 'SONG_SHEET' if you see musical notes or lyrics stanzas.

### 🧠 AGENT 2: THE PEDAGOGUE
Interpret the Agent 1 inventory.
- If Maze + Animals -> Goal: "Logic & Vocabulary".
- If "There is/are" -> Goal: "Spatial Grammar".
- Determine CEFR Level (Pre-A1 to B1).

### 🎨 AGENT 3: THE ASSET CURATOR
Identify what is missing to make this interactive.
- For every Vocabulary word found, generate 3 "Distractors" (wrong answers) for quizzes.
- For Comic Strips, extract dialogue and assign emotions for TTS generation.
- Design a prompt for a background image that matches the page's theme.

### 🏗️ AGENT 4: THE GAME MECHANIC
Map the content to our Game Engines:
1. **LOGIC_LABYRINTH**: If visual puzzles are found. Define obstacles and goals.
2. **SENTENCE_FACTORY**: If grammar tables are found. Define sentence fragments for drag-and-drop.
3. **DUBBING_STUDIO**: If comics are found. Timestamp the dialogue.
4. **FLASH_MATCH**: For vocabulary lists.
5. **MEDIA_PLAYER**: For songs.

### 🎬 AGENT 5: THE ORCHESTRATOR
Assemble the final "LessonManifest" timeline.
- Start with a Warm-up (Media/Song).
- Follow with Input (Flash Match).
- Then Practice (Sentence Factory).
- End with Production (Dubbing or Labyrinth).

**OUTPUT FORMAT:**
Return a single JSON object containing keys for all 5 agents.
`;

// --- SCHEMA DEFINITION ---
const pipelineSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    agent_1_vision: {
      type: Type.OBJECT,
      properties: {
        detected_zones: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['VISUAL_PUZZLE', 'COMIC_STRIP', 'GRAMMAR_TABLE', 'SONG_SHEET', 'VOCAB_LIST', 'READING_PASSAGE', 'ILLUSTRATION'] },
              description: { type: Type.STRING },
              text_content: { type: Type.STRING }
            },
            required: ["id", "type", "description"]
          }
        },
        overall_layout: { type: Type.STRING },
        dominating_visual: { type: Type.STRING }
      },
      required: ["detected_zones"]
    },
    agent_2_pedagogy: {
      type: Type.OBJECT,
      properties: {
        primary_topic: { type: Type.STRING },
        grammar_focus: { type: Type.STRING },
        target_skills: { type: Type.ARRAY, items: { type: Type.STRING } },
        difficulty_cefr: { type: Type.STRING, enum: ['Pre-A1', 'A1', 'A2', 'B1'] },
        educational_goal: { type: Type.STRING }
      },
      required: ["primary_topic", "educational_goal"]
    },
    agent_3_assets: {
      type: Type.OBJECT,
      properties: {
        vocabulary_enhancements: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING },
              definition: { type: Type.STRING },
              distractors: { type: Type.ARRAY, items: { type: Type.STRING } },
              image_prompt: { type: Type.STRING }
            }
          }
        },
        audio_production_queue: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              character_id: { type: Type.STRING },
              text: { type: Type.STRING },
              emotion: { type: Type.STRING }
            }
          }
        },
        background_image_prompt: { type: Type.STRING }
      },
      required: ["vocabulary_enhancements"]
    },
    agent_4_mechanics: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          engine: { type: Type.STRING, enum: ['LOGIC_LABYRINTH', 'SENTENCE_FACTORY', 'DUBBING_STUDIO', 'FLASH_MATCH', 'MEDIA_PLAYER'] },
          title: { type: Type.STRING },
          instructions: { type: Type.STRING },
          config_data: { type: Type.OBJECT, properties: { 
             items: { type: Type.ARRAY, items: { type: Type.STRING } }, 
             sentences: { type: Type.ARRAY, items: { type: Type.STRING } }
          }}
        },
        required: ["engine", "title"]
      }
    },
    agent_5_orchestrator: {
      type: Type.OBJECT,
      properties: {
        meta: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            theme: { type: Type.STRING }
          }
        },
        timeline: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              title: { type: Type.STRING },
              duration: { type: Type.INTEGER },
              data: { type: Type.OBJECT, properties: {
                 // Flexible bucket for transformed props
                 config: { type: Type.OBJECT }
              }}
            },
            required: ["type", "title"]
          }
        }
      },
      required: ["meta", "timeline"]
    }
  },
  required: ["agent_1_vision", "agent_2_pedagogy", "agent_3_assets", "agent_4_mechanics", "agent_5_orchestrator"]
};

// --- MAIN FUNCTION ---

export const analyzeTextbookPage = async (imageBase64: string): Promise<LessonManifest | null> => {
  try {
    const ai = getClient();

    console.log("🚀 Starting 5-Agent Pipeline Analysis...");

    // Use Pro model for high intelligence reasoning
    const response = await ai.models.generateContent({
      model: GEMINI_PRO_MODEL, 
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          { text: "Execute the 5-Agent Pipeline. Output valid JSON only." }
        ]
      },
      config: {
        systemInstruction: MULTI_AGENT_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: pipelineSchema
      }
    });

    const rawText = response.text || "";

    // Log raw output for debugging
    // console.log("🤖 Raw AI Output:", rawText);

    if (!rawText) throw new Error("Empty response from Gemini");

    // Clean markdown if present
    const cleanText = cleanJsonOutput(rawText);

    let pipelineOutput: AgentPipelineOutput;
    try {
      pipelineOutput = JSON.parse(cleanText) as AgentPipelineOutput;
    } catch (parseError) {
      console.error("❌ JSON Parse Failed. Cleaned Text:", cleanText);
      throw new Error("Failed to parse Gemini output as JSON.");
    }

    console.log("✅ Pipeline Success! Detected Zones:", pipelineOutput.agent_1_vision.detected_zones.length);
    console.log("✅ Orchestrator Plan:", pipelineOutput.agent_5_orchestrator.timeline.length);

    // Map to Legacy/Frontend compatible format
    const legacyManifest: LessonManifest = {
      meta: {
        unit_title: pipelineOutput.agent_5_orchestrator.meta.title || "New Lesson",
        theme: pipelineOutput.agent_5_orchestrator.meta.theme || "General",
        difficulty_cefr: pipelineOutput.agent_2_pedagogy.difficulty_cefr || "A1"
      },
      knowledge_graph: {
        characters: [], 
        vocabulary: (pipelineOutput.agent_3_assets.vocabulary_enhancements || []).map(v => ({
          word: v.word,
          definition: v.definition,
          distractors: v.distractors || [],
          image_prompt: v.image_prompt
        })),
        grammar_rules: [{ 
           rule: pipelineOutput.agent_2_pedagogy.grammar_focus || "General Usage", 
           examples: [] 
        }],
        narrative_arc: `Lesson about ${pipelineOutput.agent_2_pedagogy.primary_topic}`
      },
      timeline: pipelineOutput.agent_5_orchestrator.timeline.map(block => ({
        ...block,
        // Ensure config exists if data is missing, or map data to config
        config: block.data?.config || block.data || {} 
      }))
    };

    return legacyManifest;

  } catch (error) {
    console.error("🚨 Pipeline Failure:", error);
    return createFallbackManifest();
  }
};

// --- LEGACY HELPERS ---

const createFallbackManifest = (): LessonManifest => ({
  meta: {
    unit_title: "Scan Failed",
    theme: "Error",
    difficulty_cefr: "A1"
  },
  knowledge_graph: { characters: [], vocabulary: [], grammar_rules: [] },
  timeline: [
    {
      type: 'MEDIA_PLAYER',
      title: 'Error Recovery',
      duration: 5,
      config: { search_query: 'Happy Song' }
    }
  ]
});

export const generateSong = async (topic: string): Promise<{ title: string; lyrics: string } | null> => {
  return { title: "Song Gen Disabled", lyrics: "Feature pending..." };
};

export const generateImage = async (prompt: string): Promise<string | null> => {
  return null;
};

