import React, { useState, useRef } from 'react';
import { UploadCloud, Check, X, ArrowRight, Loader2, FileText, Trash2, Plus, AlertTriangle } from 'lucide-react';
import { MockEngine } from '../../services/MockEngine';
import { analyzeTextbookPage, LessonManifest } from '../../services/geminiService';
import { useSession } from '../../store/SessionContext';
import ReviewContent from './ReviewContent';
import AIAnalysis from './AIAnalysis';

interface UploadTextbookProps {
  onFinish?: () => void;
}

const UploadTextbook: React.FC<UploadTextbookProps> = ({ onFinish }) => {
  const { loadUnits, setActiveUnit } = useSession();
  const [isDragging, setIsDragging] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [showReview, setShowReview] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Store actual File objects now
  const [files, setFiles] = useState<File[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Store scanned blueprint to pass to review
  const [scannedBlueprint, setScannedBlueprint] = useState<LessonManifest | null>(null);

  const startScan = async () => {
    if (files.length === 0) return;
    setError(null);
    setIsScanning(true);
    // The Analysis component runs the visual timer, then calls handleAIComplete
  };

  const handleAIComplete = async () => {
    const file = files[0];
    const fileName = file?.name || "New Upload";
    let aiBlueprint: LessonManifest | null = null;

    try {
      // 1. Try Real AI Scan if file is an image
      if (file && file.type.startsWith('image/')) {
         const base64 = await resizeAndConvertImage(file);
         // Strip prefix for API
         const base64Data = base64.split(',')[1];
         aiBlueprint = await analyzeTextbookPage(base64Data);
      } else {
         // Fallback for non-images (PDFs not supported in client resize yet)
         // For now, only support images properly
         throw new Error("Please upload a JPG or PNG image.");
      }
    } catch (e: any) {
      console.error("Critical AI Scan Error:", e);
      setError(`AI Scan Failed: ${e.message || "Unknown error"}`);
      setIsScanning(false);
      return; 
    }

    if (!aiBlueprint) {
       setError("The AI could not analyze this image. Please try a clearer photo.");
       setIsScanning(false);
       return;
    }

    // 2. Create the Unit in the Database with the Blueprint
    const newUnit = await MockEngine.createUnit(aiBlueprint.meta.unit_title || fileName, aiBlueprint);

    // 3. Update Global State
    await loadUnits();
    setActiveUnit(newUnit.id);

    // 4. Pass full blueprint to review
    setScannedBlueprint(aiBlueprint);

    // 5. Move to Review Phase
    setIsScanning(false);
    setShowReview(true);
  };

  const resizeAndConvertImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.src = URL.createObjectURL(file);
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_DIMENSION = 1024; // Strict limit to prevent XHR errors
        let width = img.width;
        let height = img.height;

        // Scale down keeping aspect ratio
        if (width > height) {
          if (width > MAX_DIMENSION) {
            height *= MAX_DIMENSION / width;
            width = MAX_DIMENSION;
          }
        } else {
          if (height > MAX_DIMENSION) {
            width *= MAX_DIMENSION / height;
            height = MAX_DIMENSION;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (ctx) {
           ctx.drawImage(img, 0, 0, width, height);
           // Compress to 0.6 JPEG for smaller payload
           const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
           resolve(dataUrl);
        } else {
           reject(new Error("Could not get canvas context"));
        }
      };
      img.onerror = (e) => reject(new Error("Failed to load image"));
    });
  };

  const handlePublish = () => {
    onFinish?.();
  };

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.currentTarget.contains(e.relatedTarget as Node)) return;
    setIsDragging(false);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    e.dataTransfer.dropEffect = 'copy';
    setIsDragging(true);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const newFiles = Array.from(e.dataTransfer.files);
      setFiles(prev => [...prev, ...newFiles]);
      setError(null);
    }
  };

  const handleBrowseClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newFiles = Array.from(e.target.files);
      setFiles(prev => [...prev, ...newFiles]);
      setError(null);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  if (isScanning) {
    return <AIAnalysis onCancel={() => setIsScanning(false)} onComplete={handleAIComplete} />;
  }

  if (showReview && scannedBlueprint) {
    return <ReviewContent onBack={() => setShowReview(false)} onPublish={handlePublish} initialBlueprint={scannedBlueprint} />;
  }

  return (
    <div className="flex-1 p-8 overflow-auto flex gap-8">
      {/* Main Upload Area */}
      <div className="flex-1 max-w-4xl">
         <div className="flex items-center gap-4 mb-8">
            <div className={`flex items-center text-sm font-bold text-slate-500`}>
               <span className="w-8 h-8 rounded-full bg-teacher-primary text-white flex items-center justify-center mr-2">1</span>
               Upload
            </div>
            <div className="w-12 h-0.5 bg-slate-200"></div>
            <div className={`flex items-center text-sm font-bold text-slate-300`}>
               <span className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center mr-2">2</span>
               Processing
            </div>
            <div className="w-12 h-0.5 bg-slate-200"></div>
            <div className="flex items-center text-sm font-bold text-slate-300">
               <span className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center mr-2">3</span>
               Review
            </div>
         </div>

         <h1 className="text-3xl font-display font-bold text-slate-800 mb-2">Let's digitize your textbook</h1>
         <p className="text-slate-500 mb-8">Upload scanned pages or photos. The AI will extract activities automatically.</p>

         {error && (
            <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-3">
               <AlertTriangle size={24} />
               <div>
                  <div className="font-bold">Scan Error</div>
                  <div className="text-sm">{error}</div>
               </div>
