export const analyzeTextbookPage = async (imageBase64: string): Promise<LessonManifest | null> => {
  try {
    const ai = getClient();

    console.log("🚀 Starting 5-Agent Pipeline Analysis...");

    const commonConfig = {
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          { text: "Execute the 5-Agent Pipeline. Output valid JSON only." }
        ]
      },
      config: {
        systemInstruction: MULTI_AGENT_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: pipelineSchema
      }
    };

    let response;

    // STRATEGY: Try Pro Model -> Fallback to Flash Model
    try {
        console.log(`🤖 Attempting analysis with PRIMARY model: ${GEMINI_PRO_MODEL}`);
        response = await retryWithBackoff(async () => {
            return await ai.models.generateContent({
              model: GEMINI_PRO_MODEL, 
              ...commonConfig
            });
        }, 1, 1000); // 1 retry for Pro before giving up
    } catch (proError: any) {
        console.warn(`⚠️ Primary model failed (${proError.message}). Switching to FALLBACK model: ${GEMINI_FLASH_MODEL}`);

        // Fallback to Flash
        try {
            response = await retryWithBackoff(async () => {
                return await ai.models.generateContent({
                  model: GEMINI_FLASH_MODEL, 
                  ...commonConfig
                });
            }, 2, 1000); // 2 retries for Flash
        } catch (flashError) {
            console.error("🚨 Both models failed.");
            throw flashError; // Throw final error to trigger UI fallback
        }
    }

    const rawText = response.text || "";
    if (!rawText) throw new Error("Empty response from Gemini");

    const cleanText = cleanJsonOutput(rawText);

    let pipelineOutput: AgentPipelineOutput;
    try {
      pipelineOutput = JSON.parse(cleanText) as AgentPipelineOutput;
    } catch (parseError) {
      console.error("❌ JSON Parse Failed. Cleaned Text:", cleanText);
      throw new Error("Failed to parse Gemini output as JSON.");
    }

    console.log("✅ Pipeline Success! Detected Zones:", pipelineOutput.agent_1_vision.detected_zones?.length);

    // Map to Legacy/Frontend compatible format
    const legacyManifest: LessonManifest = {
      meta: {
        unit_title: pipelineOutput.agent_5_orchestrator.meta.title || "New Lesson",
        theme: pipelineOutput.agent_5_orchestrator.meta.theme || "General",
        difficulty_cefr: pipelineOutput.agent_2_pedagogy.difficulty_cefr || "A1"
      },
      knowledge_graph: {
        characters: [], 
        vocabulary: (pipelineOutput.agent_3_assets.vocabulary_enhancements || []).map(v => ({
          word: v.word,
          definition: v.definition,
          distractors: v.distractors || [],
          image_prompt: v.image_prompt
        })),
        grammar_rules: [{ 
           rule: pipelineOutput.agent_2_pedagogy.grammar_focus || "General Usage", 
           examples: [] 
        }],
        narrative_arc: `Lesson about ${pipelineOutput.agent_2_pedagogy.primary_topic}`
      },
      timeline: pipelineOutput.agent_5_orchestrator.timeline.map(block => ({
        ...block,
        // Ensure config exists if data is missing, or map data to config
        config: block.data?.config || block.data || {} 
      }))
    };

    return legacyManifest;

  } catch (error) {
    console.error("🚨 Pipeline Failure:", error);
    // In dev mode, return fallback to allow UI testing even if API fails
    return createFallbackManifest();
  }
};

